[Fact]
public void ShouldVerifyDefaultFormatIncludesCountWhileSupportingAlternativeAndMinimal()
{
    var table = new ConsoleTable("Column")
        .AddRow("Data 1")
        .AddRow("Data 2");

    // Verify Default format includes a total count of processed rows
    var defaultOutput = table.ToString();
    Assert.Contains("Count: 2", defaultOutput);

    // Verify support for Alternative and Minimal formats
    var alternativeOutput = table.ToStringAlternative();
    var minimalOutput = table.ToMinimalString();

    Assert.NotNull(alternativeOutput);
    Assert.NotNull(minimalOutput);
    Assert.NotEqual(defaultOutput, alternativeOutput);
    Assert.NotEqual(defaultOutput, minimalOutput);
}

[Fact]
public void UserConfiguredNumericAlignmentShouldModifyOutputPadding()
{
    var entries = new[]
    {
        new { Amount = 500 }
    };

    var table = ConsoleTable
        .From(entries)
        .Configure(options => options.NumberAlignment = Alignment.Right)
        .ToString();

    // Column 'Amount' has length 6 (header length).
    // Numeric value '500' has length 3.
    // Right alignment (width 6) produces three leading spaces before '500'.
    // ConsoleTable.Format adds an additional leading space before the value and one after the delimiter.
    // Expected row segment: |    500 |

    Assert.Contains("|    500 |", table);
}

[Fact]
public void From_ShouldAutomaticallyGenerateTableFromPocoCollection()
{
    var items = new List<Something>
    {
        new Something { Id = "1", Name = "Item1" },
        new Something { Id = "2", Name = "Item2" }
    };

    var table = ConsoleTable.From(items);

    Assert.Equal(3, table.Columns.Count);
    Assert.Equal("Id", table.Columns[0]);
    Assert.Equal("Name", table.Columns[1]);
    Assert.Equal("Date", table.Columns[2]);
    Assert.Equal(2, table.Rows.Count);
    Assert.Equal("1", table.Rows[0][0]);
    Assert.Equal("Item1", table.Rows[0][1]);
}

[Fact]
public void AddRow_ShouldThrowException_WhenValueCountDoesNotMatchColumnCount()
{
