    var exception = Assert.Throws<Exception>(() => table.AddRow("Value1"));

    Assert.Equal("The number columns in the row (2) does not match the values (1)", exception.Message);
}

[Fact]
public void ShouldWrapCellTextAndMaintainWordIntegrityWhenExceedingMaxWidth()
{
    // Arrange
    var table = new ConsoleTable("Header");
    table.MaxWidth = 8;
    table.SetWordBreakDelimiter(' ');
    // "12345 12345" has a length of 11. MaxWidth is 8.
    // cutCell would be "12345 12". lastSpace is at 5. 
    // cutCell becomes "12345", leftOver becomes " 12345".
    table.AddRow("12345 12345");

    // Act
    // ToString calls SetFormats which contains the wrapping logic
    table.ToString();

    // Assert
    // The single row should now be two rows due to wrapping
    Assert.Equal(2, table.Rows.Count);
    // First row should contain the word before the delimiter
    Assert.Equal("12345", table.Rows[0][0]);
    // Second row should contain the remaining text trimmed
    Assert.Equal("12345", table.Rows[1][0]);
}

