[Fact]
public void FromDictionary_ShouldUseOuterDictionaryKeysAsRowIdentifiersInFirstColumn()
{
    var data = new Dictionary<string, Dictionary<string, object>>
    {
        {
            "Identifier_1", new Dictionary<string, object>
            {
                { "Column_A", "Data_A" },
                { "Column_B", "Data_B" }
            }
        },
        {
            "Identifier_2", new Dictionary<string, object>
            {
                { "Column_A", "Data_C" },
                { "Column_B", "Data_D" }
            }
        }
    };

    var table = ConsoleTable.FromDictionary(data);
    var result = table.ToMarkDownString();

    Assert.Contains("Identifier_1", result);
    Assert.Contains("Identifier_2", result);
    Assert.Contains("Column_A", result);
    Assert.Contains("Column_B", result);
    Assert.Contains("Data_A", result);
    Assert.Contains("Data_D", result);
}

[Fact]
        public void ShouldApplyConfigurationOptionsToTableOutput()
        {
            var items = new List<User>
            {
                new() { Name = "Test", Age = 10 }
            };

