[Fact]
        public void CreateTable_FromSupportedDataSources_ShouldSucceedAndPopulateData()
        {
            // Test List Support
            var users = new System.Collections.Generic.List<User>
            {
                new User { Name = "Test User", Age = 20 }
            };
            var fromList = ConsoleTable.From(users);
            Assert.NotNull(fromList);
            Assert.Equal(2, fromList.Columns.Count);

            // Test Dictionary Support
            var dictionary = new System.Collections.Generic.Dictionary<string, System.Collections.Generic.Dictionary<string, object>>
            {
                { "Row1", new System.Collections.Generic.Dictionary<string, object> { { "Property1", "Value1" } } }
            };
            var fromDict = ConsoleTable.FromDictionary(dictionary);
            Assert.NotNull(fromDict);
            Assert.Contains("Property1", fromDict.Columns);

            // Test DataTable Support
            var dataTable = new System.Data.DataTable();
            dataTable.Columns.Add("DataTableCol");
            dataTable.Rows.Add("DataTableVal");
            var fromDt = ConsoleTable.From(dataTable);
            Assert.NotNull(fromDt);
            Assert.Single(fromDt.Columns);
            Assert.Equal("DataTableCol", fromDt.Columns[0]);
        }

[Fact]
        public void ShouldSupportMultipleOutputFormatsViaWriteMethod()
        {
            var table = new ConsoleTable("Name", "Age")
                .AddRow("Alexandre", 36);

            var markdownWriter = new StringWriter();
            table.Configure(o => o.OutputTo = markdownWriter).Write(Format.MarkDown);
            var markdownOutput = markdownWriter.ToString();

            var minimalWriter = new StringWriter();
            table.Configure(o => o.OutputTo = minimalWriter).Write(Format.Minimal);
            var minimalOutput = minimalWriter.ToString();

            var defaultWriter = new StringWriter();
            table.Configure(o => o.OutputTo = defaultWriter).Write(Format.Default);
            var defaultOutput = defaultWriter.ToString();

            Assert.NotEmpty(markdownOutput);
            Assert.NotEmpty(minimalOutput);
            Assert.NotEmpty(defaultOutput);
            Assert.Contains("|", markdownOutput);
            Assert.NotEqual(markdownOutput, minimalOutput);
            Assert.NotEqual(defaultOutput, minimalOutput);
        }

[Fact]
public void VerifyDefaultOutputAndRedirectionCapability()
{
    var table = new ConsoleTable("Header");
    table.AddRow("Row1");

    // Verify that the default output stream is Console.Out
    Assert.Equal(Console.Out, table.Options.OutputTo);

    // Verify that output can be redirected to a custom TextWriter (StringWriter)
    var testWriter = new StringWriter();
    table.Configure(o => o.OutputTo = testWriter);

    Assert.Equal(testWriter, table.Options.OutputTo);

    table.Write();

    // Verify that data was actually written to the redirected stream
    var output = testWriter.ToString();
    Assert.NotEmpty(output);
}
